  @protected
  void sse_encode_frb_bench_event(
    FrbBenchEvent self,
    SseSerializer serializer,
  ) {
    // Codec=Sse (Serialization based), see doc to use other codecs
    switch (self) {
      case FrbBenchEvent_StateChanged(from: final from, to: final to):
        sse_encode_i_32(0, serializer);
        sse_encode_String(from, serializer);
        sse_encode_String(to, serializer);
      case FrbBenchEvent_Sample(field0: final field0):
        sse_encode_i_32(1, serializer);
        sse_encode_box_autoadd_frb_resource_sample(field0, serializer);
      case FrbBenchEvent_Token(index: final index, text: final text):
        sse_encode_i_32(2, serializer);
        sse_encode_u_32(index, serializer);
        sse_encode_String(text, serializer);
      case FrbBenchEvent_WatchdogWarn():
        sse_encode_i_32(3, serializer);
      case FrbBenchEvent_WatchdogKill():
        sse_encode_i_32(4, serializer);
      case FrbBenchEvent_RunFinished(
        runId: final runId,
        status: final status,
        result: final result,
      ):
        sse_encode_i_32(5, serializer);
        sse_encode_u_64(runId, serializer);
        sse_encode_String(status, serializer);
        sse_encode_opt_box_autoadd_frb_bench_result(result, serializer);
      case FrbBenchEvent_Log(level: final level, message: final message):
        sse_encode_i_32(6, serializer);
        sse_encode_String(level, serializer);
        sse_encode_String(message, serializer);
      case FrbBenchEvent_Progress(message: final message):
        sse_encode_i_32(7, serializer);
        sse_encode_String(message, serializer);
    }
  }

